from osf.utils.workflows import ChoiceEnum, DefaultStates


@unique
class Workflows(ChoiceEnum):
    NONE = None
    PRE_MODERATION = 'pre-moderation'  # moderation before approval
    POST_MODERATION = 'post-moderation'  # moderation after approval
    HYBRID_MODERATION = 'hybrid-moderation'  # moderation after approval moderator/admin, moderation before for everyone else

PUBLIC_STATES = {
    Workflows.NONE.value: (
        DefaultStates.INITIAL.value,
        DefaultStates.PENDING.value,
        DefaultStates.ACCEPTED.value,
        DefaultStates.REJECTED.value,
    ),
    Workflows.PRE_MODERATION.value: (
        DefaultStates.ACCEPTED.value,
    ),
    Workflows.POST_MODERATION.value: (
        DefaultStates.PENDING.value,
        DefaultStates.ACCEPTED.value,
    ),
    Workflows.HYBRID_MODERATION.value: (
        DefaultStates.ACCEPTED.value,
    ),
}

import re


class UniformTrivyVulnID:
    def return_uniformed_vulnid(self, vulnid):
        if vulnid is None:
            return vulnid
        if "cve" in vulnid.lower():
            return vulnid
        if "khv" in vulnid.lower():
            temp = re.compile(r"([a-zA-Z-_]+)([0-9]+)")
            number = str(temp.match(vulnid).groups()[1]).zfill(3)
            avd_category = str(temp.match(vulnid.lower()).groups()[0])
            return avd_category.upper() + number
        if "ksv" in vulnid.lower() or "kcv" in vulnid.lower():
            temp = re.compile(r"([a-zA-Z-_]+)([0-9]+)")
            number = str(temp.match(vulnid).groups()[1]).zfill(4)
            avd_category = str(temp.match(vulnid.lower().replace("_", "").replace("-", "")).groups()[0].replace("avd", ""))
            return "AVD-" + avd_category.upper() + "-" + number
        return vulnid

from django.contrib.auth.hashers import UNUSABLE_PASSWORD_PREFIX, identify_hasher
from django.template import Library
from django.utils.html import format_html, format_html_join
from django.utils.translation import gettext

register = Library()


@register.simple_tag
def render_password_as_hash(value):
    if not value or value.startswith(UNUSABLE_PASSWORD_PREFIX):
        return format_html("<p><strong>{}</strong></p>", gettext("No password set."))
    try:
        hasher = identify_hasher(value)
        hashed_summary = hasher.safe_summary(value)
    except ValueError:
        return format_html(
            "<p><strong>{}</strong></p>",
            gettext("Invalid password format or unknown hashing algorithm."),
        )
    items = [(gettext(key), val) for key, val in hashed_summary.items()]
    return format_html(
        "<p>{}</p>",
        format_html_join(" ", "<strong>{}</strong>: <bdi>{}</bdi>", items),
    )

class Registry:
    def __init__(self):
        self._registry = {}
        self._field_registry = {}

    def register(self, cls):
        from .types import DjangoObjectType

        assert issubclass(
            cls, DjangoObjectType
        ), f'Only DjangoObjectTypes can be registered, received "{cls.__name__}"'
        assert cls._meta.registry == self, "Registry for a Model have to match."
        # assert self.get_type_for_model(cls._meta.model) == cls, (
        #     'Multiple DjangoObjectTypes registered for "{}"'.format(cls._meta.model)
        # )
        if not getattr(cls._meta, "skip_registry", False):
            self._registry[cls._meta.model] = cls

    def get_type_for_model(self, model):
        return self._registry.get(model)

    def register_converted_field(self, field, converted):
        self._field_registry[field] = converted

    def get_converted_field(self, field):
        return self._field_registry.get(field)


registry = None


def get_global_registry():
    global registry
    if not registry:
        registry = Registry()
    return registry


def reset_global_registry():
    global registry
    registry = None

